cadishfile:
example.com, adult.example.com {
    @host_x host adult.example.com
    @path_y path /cams
    @exempt cookie vip
    @prem   cookie premium
    classify {tier} {
        when @prem -> gold
        default    -> free
    }
    @isgold classify {tier}==gold
    @a all @host_x @path_y !@exempt @isgold
    pass @a
    cache_key method host path
    cache_ttl default ttl 1m
    header +cache_status X-Cache
}
